create table dirkspzm32.pzm_konten (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    pers_nr              number(*, 0) not null enable,
    konto_nr             number(*, 5) not null enable,
    name                 varchar2(100 char) not null enable,
    name_kurz            varchar2(10 char) not null enable,
    typ                  varchar2(10 char) default 'ZK' not null enable,
    buch_einheit         varchar2(30 char) not null enable,
    saldo                number(*, 5) default 0 not null enable,
    letzte_buchung       date,
    letzter_abschluss_am date,
    abschluss_saldo      number(*, 5),
    info                 varchar2(500 char),
    max_saldo            number(*, 5),
    min_saldo            number(*, 5) default 0,
    aktiv                varchar2(1 char) default 'T' not null enable,
    anspruch             number(*, 0) default 0
);

alter table dirkspzm32.pzm_konten
    add constraint pk_pzm_konten
        primary key ( konto_nr,
                      firma_nr,
                      sid )
            using index enable;


